import{_ as s,o as t,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Mechanics Assessments","description":"","frontmatter":{},"headers":[],"relativePath":"practice/mechanics-assessments.md","filePath":"practice/mechanics-assessments.md"}'),i={name:"practice/mechanics-assessments.md"};function r(o,e,c,l,h,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="mechanics-assessments" tabindex="-1">Mechanics Assessments <a class="header-anchor" href="#mechanics-assessments" aria-label="Permalink to &quot;Mechanics Assessments&quot;">​</a></h1><p>Mechanics assessments are conducted during Individual Practice sessions. They capture technique scores that appear in the Mechanics Analytics section of each player&#39;s profile.</p><h2 id="how-to-conduct-an-assessment" tabindex="-1">How to Conduct an Assessment <a class="header-anchor" href="#how-to-conduct-an-assessment" aria-label="Permalink to &quot;How to Conduct an Assessment&quot;">​</a></h2><ol><li>Start an Individual Practice session and select the player</li><li>From the Practice Hub tap <strong>Mechanics Assessment</strong></li><li>Select the mechanics area to assess: Hitting, Pitching, Fielding, or Baserunning</li><li>Work through each element, scoring 0–3</li><li>Add optional notes for any element</li><li>Tap <strong>Save Assessment</strong> when complete</li></ol><p>You can assess multiple areas in the same session — return to the Practice Hub between each assessment and start a new one.</p><h2 id="scoring-each-element" tabindex="-1">Scoring Each Element <a class="header-anchor" href="#scoring-each-element" aria-label="Permalink to &quot;Scoring Each Element&quot;">​</a></h2><p>Use the 0–3 scale for each element:</p><table tabindex="0"><thead><tr><th>Score</th><th>Meaning</th></tr></thead><tbody><tr><td>0</td><td>Not observed</td></tr><tr><td>1</td><td>Needs significant work</td></tr><tr><td>2</td><td>Developing</td></tr><tr><td>3</td><td>Correct</td></tr></tbody></table><p><strong>0 (Not observed)</strong> is for situations where you could not evaluate the element — player was wearing catching gear, the drill did not include that phase, etc. A 0 does not count against the player&#39;s average for that element.</p><h2 id="assessment-notes" tabindex="-1">Assessment Notes <a class="header-anchor" href="#assessment-notes" aria-label="Permalink to &quot;Assessment Notes&quot;">​</a></h2><p>Each element has a notes field. Use it to document what specifically you observed — this note appears in the player&#39;s mechanics history and can be referenced when writing report card comments.</p><p>Good note: &quot;Hip rotation initiates before hands — timing issue, not flexibility&quot; Poor note: &quot;Needs work&quot;</p><h2 id="viewing-assessment-results" tabindex="-1">Viewing Assessment Results <a class="header-anchor" href="#viewing-assessment-results" aria-label="Permalink to &quot;Viewing Assessment Results&quot;">​</a></h2><p>Assessment results appear immediately in the player&#39;s analytics under <strong>Mechanics</strong>. The radar chart updates with each new assessment. After 3 or more assessments trend charts become available showing improvement over time.</p><h2 id="softball-vs-baseball" tabindex="-1">Softball vs Baseball <a class="header-anchor" href="#softball-vs-baseball" aria-label="Permalink to &quot;Softball vs Baseball&quot;">​</a></h2><p>Pitching mechanics assessments use sport-specific elements. Softball assessments cover the windmill delivery (arm circle, stride, hip drive, release, follow-through). Baseball assessments cover the traditional delivery (balance, stride, arm action, rotation, finish). Select the correct sport when creating your team — assessments adjust automatically.</p>',16)])])}const u=s(i,[["render",r]]);export{p as __pageData,u as default};
